import json
import azure.functions as func

app = func.FunctionApp(http_auth_level=func.AuthLevel.ANONYMOUS)

@app.function_name(name="Api")
@app.route(route="{*path}", methods=["GET", "POST", "PUT", "PATCH", "DELETE", "OPTIONS"])
def api(req: func.HttpRequest) -> func.HttpResponse:
    headers = {
        "Access-Control-Allow-Origin": "*",
        "Access-Control-Allow-Methods": "GET, POST, PUT, PATCH, DELETE, OPTIONS",
        "Access-Control-Allow-Headers": "*",
        "Access-Control-Max-Age": "86400",
        "Content-Type": "application/json",
    }

    if req.method == "OPTIONS":
        return func.HttpResponse(status_code=204, headers=headers)

    body = {
        "message": "Azure Function HTTP API is running",
        "method": req.method,
        "path": req.route_params.get("path", ""),
        "query": dict(req.params),
    }

    try:
        if req.get_body():
            body["body"] = req.get_json()
    except ValueError:
        raw = req.get_body()
        if raw:
            body["body"] = raw.decode("utf-8", errors="replace")

    return func.HttpResponse(
        body=json.dumps(body),
        status_code=200,
        headers=headers,
    )

